const sensores = [
  { id: "066899a2-7b88-4187-84de-e4d13551a954", tipo: "condutividade" },
  { id: "2874c0c1-da70-4856-a8c8-4f5e98a67215", tipo: "umidade_ar" },
  { id: "3a65d5ad-95fc-4e84-833e-0cb27e9702ee", tipo: "nivel_agua" },
  { id: "5ec5bc8d-8e68-4d6f-8641-e5220b300000", tipo: "temperatura_agua" },
  { id: "6b4b2384-e6f7-48d3-aec6-1beca4539a01", tipo: "temperatura_ambiente" },
  { id: "42619cf4-297b-4132-abea-e7e8cb21dcd5", tipo: "umidade_solo" },
  { id: "df52ffba-5deb-4b21-b695-b80f14dce78d", tipo: "ph" },
  { id: "e035f75e-5df8-40dd-b983-9b9c42d06385", tipo: "oxigenio" },
  { id: "f753ad8a-5725-46ba-ba6e-f879a7c66eeb", tipo: "fluxo_agua" }
];

function gerarValor(tipo) {
  if (tipo === "condutividade") return 1000 + Math.random() * 10;
  if (tipo === "umidade_ar") return 80 + Math.random() * 3;
  if (tipo === "nivel_agua") return 70 + Math.random() * 3;
  if (tipo === "temperatura_agua") return 24 + Math.random() * 4;
  if (tipo === "temperatura_ambiente") return 28 + Math.random() * 4;
  if (tipo === "umidade_solo") return 70 + Math.random() * 4;
  if (tipo === "ph") return 6.5 + Math.random() * 0.5;
  if (tipo === "oxigenio") return 6 + Math.random() * 2;
  if (tipo === "fluxo_agua") return 8 + Math.random() * 2;
}

// cria múltiplas mensagens
let msgs = sensores.map(sensor => {
    return {
        payload: {
            sensor_id: sensor.id,
            valor: Number(gerarValor(sensor.tipo).toFixed(2)),
            timestamp: new Date().toISOString()
        }
    };
});

return [msgs];
